from elasticsearch import Elasticsearch
import logging
import json
from datetime import datetime
from typing import Dict, List, Any

class CentralizedLogger:
    def __init__(self, es_host: str = "localhost:9200"):
        self.es = Elasticsearch([es_host])
        self.logger = self._setup_logger()
        
    def _setup_logger(self) -> logging.Logger:
        logger = logging.getLogger("centralized_logger")
        logger.setLevel(logging.INFO)
        
        if not logger.handlers:
            handler = logging.StreamHandler()
            formatter = logging.Formatter(
                '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
            )
            handler.setFormatter(formatter)
            logger.addHandler(handler)
            
        return logger
    
    def index_document(self, index_name: str, document: Dict[str, Any]) -> bool:
        try:
            doc_id = document.get('id') or None
            response = self.es.index(
                index=index_name,
                id=doc_id,
                body=document
            )
            self.logger.info(f"Document indexed successfully: {response['_id']}")
            return True
        except Exception as e:
            self.logger.error(f"Failed to index document: {str(e)}")
            return False
    
    def search_documents(self, index_name: str, query: Dict[str, Any]) -> List[Dict[str, Any]]:
        try:
            response = self.es.search(index=index_name, body=query)
            hits = response['hits']['hits']
            results = [hit['_source'] for hit in hits]
            self.logger.info(f"Search completed. Found {len(results)} documents")
            return results
        except Exception as e:
            self.logger.error(f"Search failed: {str(e)}")
            return []
    
    def aggregate_logs(self, index_name: str, aggregation_query: Dict[str, Any]) -> Dict[str, Any]:
        try:
            response = self.es.search(index=index_name, body=aggregation_query)
            return response
        except Exception as e:
            self.logger.error(f"Log aggregation failed: {str(e)}")
            return {}
    
    def create_index(self, index_name: str, settings: Dict[str, Any] = None) -> bool:
        try:
            if not self.es.indices.exists(index=index_name):
                if settings:
                    self.es.indices.create(index=index_name, body=settings)
                else:
                    self.es.indices.create(index=index_name)
                self.logger.info(f"Index created: {index_name}")
            else:
                self.logger.info(f"Index already exists: {index_name}")
            return True
        except Exception as e:
            self.logger.error(f"Failed to create index: {str(e)}")
            return False

